css:
.site-header {
  background: #fff;
  border-bottom: 1px solid #e5e7eb;
}

.header-inner {
  max-width: 1000px;
  margin: 0 auto;
  padding: 0 20px;
  height: 56px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-logo {
  font-size: 1.1rem;
  font-weight: 700;
  color: #111;
  text-decoration: none;
}

.site-nav ul {
  list-style: none;
  display: flex;
  gap: 24px;
  margin: 0;
  padding: 0;
}

.site-nav a {
  text-decoration: none;
  color: #374151;
  font-size: 0.9rem;
}

.site-nav a:hover { color: #f97316; }

.hamb-btn {
  display: none;
  flex-direction: column;
  gap: 5px;
  width: 32px;
  background: none;
  border: none;
  cursor: pointer;
  padding: 4px;
}

.hamb-btn span {
  display: block;
  width: 100%;
  height: 2px;
  background: #374151;
}

@media (max-width: 768px) {
  .hamb-btn { display: flex; }
  .header-inner { flex-wrap: wrap; height: auto; padding: 12px 20px; }
  .site-nav { display: none; width: 100%; }
  .site-nav.open { display: block; }
  .site-nav ul { flex-direction: column; gap: 0; padding: 8px 0; }
  .site-nav a { display: block; padding: 10px 0; border-top: 1px solid #f3f4f6; text-align: right; }
}
